class BookMyShow {
public:
    vector<vector<bool>> seats;
    BookMyShow(int n, int m) {
        seats.resize(n, vector<bool>(m, false));
    }

    vector<int> gather(int k, int maxRow) {
        for (int i = 0; i <= maxRow; i++) {
            for (int j = 0; j <= seats[i].size() - k; j++) {
                bool valid = true;
                for (int l = 0; l < k; l++) {
                    if (seats[i][j + l]) {
                        valid = false;
                        break;
                    }
                }
                if (valid) {
                    for (int l = 0; l < k; l++) {
                        seats[i][j + l] = true;
                    }
                    return {i, j};
                }
            }
        }
        return {};
    }

    bool scatter(int k, int maxRow) {
        int count = 0;
        for (int i = 0; i <= maxRow; i++) {
            for (int j = 0; j < seats[i].size(); j++) {
                if (!seats[i][j]) {
                    seats[i][j] = true;
                    count++;
                    if (count == k) {
                        return true;
                    }
                }
            }
        }
        return false;
    }
};

